import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';

// 案例数据应该与HomePage共享同一数据源
const caseDetails = {
  1: { /* 案例1数据 */ },
  2: { /* 案例2数据 */ },
  3: { /* 案例3数据 */ },
  4: { /* 案例4数据 */ }
};

export default function CaseDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  
  // 严格类型转换和有效性检查
  const caseId = parseInt(id, 10);
  const isValidCase = caseId >= 1 && caseId <= Object.keys(caseDetails).length;
  const currentCase = isValidCase ? caseDetails[caseId] : null;

  // 无效ID处理
  if (!currentCase) {
    return (
      <div className="content-card">
        <div style={styles.container}>
          <h2>Case Not Found</h2>
          <button onClick={() => navigate('/')}>Back to Home</button>
        </div>
      </div>
    );
  }

  return (
    <div className="content-card">
      {/* 原有详情渲染逻辑 */}
    </div>
  );
}

const styles = {
  container: {
    padding: '1.5em',
    maxWidth: '800px',
    margin: '0 auto',
  },
  backButton: {
    background: 'none',
    border: 'none',
    color: '#0288d1',
    cursor: 'pointer',
    fontSize: '1em',
    marginBottom: '1.5em',
    padding: '0.5em 1em',
    borderRadius: '6px',
    transition: 'all 0.2s',
    ':hover': {
      backgroundColor: '#e1f5fe'
    }
  },
  title: {
    color: '#00796b',
    fontSize: '1.8em',
    marginBottom: '1em',
    textAlign: 'center'
  },
  imageContainer: {
    margin: '1.5em 0',
    textAlign: 'center'
  },
  image: {
    maxWidth: '100%',
    borderRadius: '10px',
    boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
    border: '2px solid #b2ebf2'
  },
  section: {
    margin: '2em 0'
  },
  sectionTitle: {
    color: '#0288d1',
    fontSize: '1.3em',
    marginBottom: '0.8em',
    borderBottom: '2px solid #b2ebf2',
    paddingBottom: '0.3em'
  },
  description: {
    lineHeight: '1.6',
    fontSize: '1.1em',
    color: '#333'
  },
  lessonsList: {
    paddingLeft: '1.5em'
  },
  lessonItem: {
    margin: '0.8em 0',
    lineHeight: '1.5',
    display: 'flex',
    alignItems: 'flex-start'
  },
  bullet: {
    color: '#0288d1',
    marginRight: '0.5em',
    fontSize: '1.2em'
  },
  navigation: {
    display: 'flex',
    justifyContent: 'space-between',
    marginTop: '2em'
  },
  navButton: {
    backgroundColor: '#4fb3bf',
    color: 'white',
    border: 'none',
    padding: '0.8em 1.5em',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '1em',
    transition: 'all 0.2s',
    ':hover': {
      backgroundColor: '#00838f'
    },
    ':disabled': {
      backgroundColor: '#bdbdbd',
      cursor: 'not-allowed'
    }
  }
};
